let sb=null,user=null,current="dashboard",selectedDate=today(),activeFolder="all",draggedCompany=null,saveTimer=null,signedCache=new Map();
let filters={empresas:"all",alumnos:"all",convenios:"all",seguimiento:"all",expedientes:"all",practicas:{estado:"todas",empresa:"todas",alumno:"",fecha:""}};
let state=emptyState();
function emptyState(){return{empresas:[],alumnos:[],convenios:[],documentos:[],carpetas:[{id:"all",nombre:"Todas"},{id:"sin",nombre:"Sin carpeta"},{id:"curso",nombre:"Curso 2025/26"},{id:"conv",nombre:"Convenios"}],seguimientos:[],emails:[],actividad:[]}}
function uid(){return String(Date.now()+Math.floor(Math.random()*99999))} function today(){return new Date().toISOString().slice(0,10)} function datePlus(n){const d=new Date();d.setDate(d.getDate()+n);return d.toISOString().slice(0,10)} function esc(s=""){return String(s??"").replace(/[&<>"']/g,m=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[m]))}
function toast(t){const el=$("#toast");el.textContent=t;el.classList.add("show");setTimeout(()=>el.classList.remove("show"),1800)} function setSync(t,c="ok"){const el=$("#syncStatus");if(el){el.className="sync "+c;el.innerHTML=`<i></i> ${t}`}} function safeFileName(n){return String(n||"archivo").normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/[^a-zA-Z0-9._-]+/g,"-").slice(0,120)||"archivo"}
function initSupabase(){if(!window.supabase){setAuth("No se cargó Supabase. Revisa conexión.", "error");return null} if(!sb) sb=window.supabase.createClient(SUPABASE_URL,SUPABASE_KEY,{auth:{persistSession:true,autoRefreshToken:true,detectSessionInUrl:true}}); return sb}
function setAuth(t,c="info"){const el=$("#authStatus");if(el){el.className="auth-status "+c;el.textContent=t}}
async function login(mode){initSupabase();const email=$("#loginEmail").value.trim(),password=$("#loginPassword").value;if(!email||!password){setAuth("Introduce email y contraseña.","error");return}try{setAuth(mode==="signup"?"Creando cuenta...":"Entrando...");const res=mode==="signup"?await sb.auth.signUp({email,password}):await sb.auth.signInWithPassword({email,password});if(res.error)throw res.error;await bootstrap()}catch(e){setAuth(e.message||"No se pudo entrar.","error")}}
async function magic(){initSupabase();const email=$("#loginEmail").value.trim();if(!email)return setAuth("Introduce email.","error");const {error}=await sb.auth.signInWithOtp({email,options:{emailRedirectTo:location.href.split("#")[0]}});setAuth(error?error.message:"Revisa tu correo para entrar.", error?"error":"ok")}
async function logout(){await sb.auth.signOut();user=null;state=emptyState();document.body.classList.add("locked");setAuth("Sesión cerrada.")}
async function bootstrap(){initSupabase();const {data}=await sb.auth.getUser();user=data.user;if(!user){document.body.classList.add("locked");return}document.body.classList.remove("locked");setAuth("Sesión activa.","ok");await loadAll();show(current||"dashboard");}
function rowFrom(e){const data=strip(e);return{id:String(e.id),owner_id:user.id,nombre:e.nombre||e.empresa||"",empresa:e.empresa||"",sector:e.sector||"",estado:e.estado||"",tipo:e.tipo||"",fecha:e.fecha||null,fecha_proxima:e.fechaProxima||null,carpeta:e.carpeta?String(e.carpeta):null,data}}
function strip(v){if(Array.isArray(v))return v.map(strip);if(v&&typeof v==="object"){const o={};for(const[k,val]of Object.entries(v)){if(k==="data"&&typeof val==="string"&&val.startsWith("data:"))continue;o[k]=strip(val)}return o}return v}
async function loadTable(key){const {data,error}=await sb.from(TABLES[key]).select("data").order("updated_at",{ascending:false});if(error){console.error(error);throw error}return (data||[]).map(r=>r.data)}
async function loadAll(){setSync("Cargando privado...","saving");try{const loaded=emptyState();for(const k of ["empresas","alumnos","convenios","documentos","seguimientos","emails","actividad"]){loaded[k]=await loadTable(k)}const folders=await loadTable("carpetas");loaded.carpetas=[{id:"all",nombre:"Todas"},{id:"sin",nombre:"Sin carpeta"},...(folders.length?folders:[{id:"curso",nombre:"Curso 2025/26"},{id:"conv",nombre:"Convenios"}])];state=loaded;setSync("Privado sincronizado","ok")}catch(e){setSync("Error carga","error");alert("Error cargando datos. ¿Ejecutaste el SQL de Bloom CRM 5.0?\n\n"+e.message)}}
async function saveTable(key){const arr=(state[key]||[]).filter(x=>x.id&&x.id!=="all"&&x.id!=="sin").map(rowFrom);if(!arr.length)return;const {error}=await sb.from(TABLES[key]).upsert(arr,{onConflict:"id"});if(error)throw error}
function scheduleSave(){if(!user)return;clearTimeout(saveTimer);setSync("Guardando...","saving");saveTimer=setTimeout(saveAll,450)}
async function saveAll(){try{for(const k of ["empresas","alumnos","convenios","documentos","carpetas","seguimientos","emails","actividad"])await saveTable(k);setSync("Privado sincronizado","ok")}catch(e){console.error(e);setSync("Error guardado","error");alert("Error guardando:\n\n"+e.message)}}
function log(t){state.actividad.unshift({id:uid(),txt:t,fecha:new Date().toISOString()});state.actividad=state.actividad.slice(0,80)}
async function uploadFile(file,folder="general"){if(!file||!user)return null;const path=`${user.id}/${folder}/${new Date().getFullYear()}/${Date.now()}-${safeFileName(file.name)}`;setSync("Subiendo archivo...","saving");const {data,error}=await sb.storage.from(STORAGE_BUCKET).upload(path,file,{upsert:true,contentType:file.type||"application/octet-stream"});if(error){setSync("Error Storage","error");alert("Error subiendo archivo. Revisa bucket privado y policies.\n\n"+error.message);return null}setSync("Archivo subido","ok");return{name:file.name,type:file.type||"",size:file.size||0,path:data.path,private:true,storage:true}}
async function signedUrl(path){if(!path)return"";const c=signedCache.get(path);if(c&&c.exp>Date.now()+30000)return c.url;const {data,error}=await sb.storage.from(STORAGE_BUCKET).createSignedUrl(path,300);if(error){console.error(error);return""}signedCache.set(path,{url:data.signedUrl,exp:Date.now()+300000});return data.signedUrl}
function show(v){current=v;$$(".view").forEach(x=>x.classList.toggle("active",x.id===v));$$("#nav button").forEach(b=>b.classList.toggle("active",b.dataset.view===v));render();if(innerWidth<820)$("#sidebar").classList.remove("open")}
function render(){if(!user)return;updateIcons();updatePlant();renderDashboard();renderEmpresas();renderAlumnos();renderPracticas();renderConvenios();renderExpedientes();renderDocumentos();renderSeguimiento();renderEmails();renderAgenda();renderReportes();renderAjustes();renderNotifications();setupPipeline()}
function updateIcons(){$$("[data-i]").forEach(s=>s.innerHTML=icons[s.dataset.i]||"")} function pageHead(p,h,s){return `<div class="page-head"><div><p>${p}</p><h2>${h}</h2><span>${s}</span></div><button class="date-pill">${new Date().toLocaleDateString("es-ES",{day:"numeric",month:"long",year:"numeric"})}</button></div>`}
function updatePlant(){const un=state.alumnos.filter(a=>!a.empresa).length,pen=state.convenios.filter(c=>c.estado!=="firmado"&&c.estado!=="completo").length;$("#plantTitle").textContent=un?`${un} alumno${un>1?"s":""} esperan una oportunidad.`:pen?`${pen} convenio${pen>1?"s":""} puede${pen>1?"n":""} florecer.`:"Que hoy florezcan nuevas oportunidades.";$("#plantMessage").textContent=un?"Una buena asignación puede cambiarlo todo.":pen?"Revisar lo pendiente también es avanzar.":"Cada pequeño paso también cuenta."}
function greeting(){const h=new Date().getHours();return `${h<14?"Buenos días":h<21?"Buenas tardes":"Buenas noches"} 🌸 | Aquí tienes tu resumen de hoy`} function kpi(l,v,view,color,icon,filter){return `<article class="kpi card" onclick="${view==='agenda'?`selectedDate=firstReminderDate();show('agenda')`:`filters.${view}='${filter||"all"}';show('${view}')`}"><div class="kpi-icon ${color}">${icons[icon]}</div><strong>${v}</strong><span>${l}</span></article>`}
function firstReminderDate(){return state.seguimientos.filter(s=>s.fechaProxima>=today()).sort((a,b)=>a.fechaProxima.localeCompare(b.fechaProxima))[0]?.fechaProxima||today()}
function dashboardData(){return{sinContacto:state.empresas.filter(e=>!state.seguimientos.some(s=>s.empresa===e.nombre)).length,convenios:state.convenios.filter(c=>c.estado!=="firmado"&&c.estado!=="completo").length,alumnos:state.alumnos.filter(a=>!a.empresa).length,practicas:state.alumnos.filter(a=>a.estado==="prácticas").length,llamadas:state.seguimientos.filter(s=>s.tipo==="llamada").length,reuniones:state.seguimientos.filter(s=>s.tipo==="reunión").length,recordatorios:state.seguimientos.filter(s=>s.fechaProxima>=today()).length}}
function renderDashboard(){const d=dashboardData();$("#dashboard").innerHTML=pageHead("Dashboard","Dashboard",greeting())+`<section class="kpi-grid">${kpi("Empresas sin contactar",d.sinContacto,"empresas","pink","users","sinSeguimiento")}${kpi("Convenios pendientes",d.convenios,"convenios","orange","file","pendientes")}${kpi("Alumnos sin empresa",d.alumnos,"alumnos","blue","student","sinEmpresa")}${kpi("Prácticas activas",d.practicas,"practicas","green","briefcase","activas")}${kpi("Llamadas registradas",d.llamadas,"seguimiento","purple","phone","llamadas")}${kpi("Reuniones",d.reuniones,"seguimiento","blue","calendar","reuniones")}${kpi("Recordatorios activos",d.recordatorios,"agenda","pink","calendar","all")}</section><section class="dashboard-grid"><div><section class="card pipeline"><div class="section-head"><div><p>Pipeline de empresas</p><h3>Arrastra empresas entre estados</h3></div><button onclick="show('empresas')">Ver empresas</button></div><div class="mini-pipeline">${renderMiniPipeline()}</div></section><div class="lower-grid"><section class="card"><div class="section-head"><div><p>Actividad reciente</p><h3>Últimos movimientos</h3></div></div><div class="list">${state.actividad.slice(0,5).map(a=>`<article class="item" onclick="openActivityTarget('${esc(a.txt).replaceAll("'","\\'")}')"><div><b>${esc(a.txt)}</b><p>${new Date(a.fecha).toLocaleString("es-ES")}</p></div><span>Ir</span></article>`).join("")||"<p>Sin actividad reciente.</p>"}</div></section><section class="card"><div class="section-head"><div><p>Documentos pendientes</p><h3>Revisión documental</h3></div><button onclick="show('documentos')">Ver todos</button></div><div class="list">${state.documentos.filter(x=>x.estado!=="firmado").slice(0,5).map(d=>`<article class="item" onclick="previewAnyFile(state.documentos.find(x=>x.id==='${d.id}').file,'${esc(d.nombre)}')"><div><b>${esc(d.nombre)}</b><p>${esc(d.tipo)} · ${esc(d.empresa||d.alumno||"General")}</p></div><span>Ver</span></article>`).join("")||"<p>Sin documentos pendientes.</p>"}</div></section></div></div><aside class="right-stack"><section class="card calendar-card"><div class="section-head"><div><p>Calendario</p><h3>Este mes</h3></div><button onclick="show('agenda')">Completo</button></div>${miniCalendar()}</section><section class="card actions-card"><div class="section-head"><div><p>Próximas acciones</p><h3>Hoy y próximos días</h3></div></div><div class="list">${state.seguimientos.filter(s=>s.fechaProxima>=today()).slice(0,5).map(actionItem).join("")||"<p>No hay pendientes.</p>"}</div></section></aside></section>`}
function renderMiniPipeline(){const estados=[["nueva","Nueva"],["contactada","Contactada"],["interesada","Interesada"],["convenio","Convenio"],["activa","Activa"]];return estados.map(([st,label],idx)=>{const companies=state.empresas.filter(e=>e.estado===st);return `<div class="pipe-col drop-zone" data-status="${st}"><h4>${label}<span>${companies.length}</span></h4><div class="drop-msg">Suelta aquí</div>${companies.map(e=>`<div class="company-card" draggable="true" data-company="${e.id}" onclick="event.stopPropagation();openEmpresa360('${e.id}')"><b>${esc(e.nombre)}</b><small>${esc(e.sector)} · ${esc(e.contacto)}</small><em>${esc(e.prioridad||"media")}</em><div class="pipeline-actions" onclick="event.stopPropagation()">${idx>0?`<button onclick="moveCompany('${e.id}','${estados[idx-1][0]}')">←</button>`:""}${idx<estados.length-1?`<button onclick="moveCompany('${e.id}','${estados[idx+1][0]}')">→</button>`:""}</div></div>`).join("")||`<p class="empty-pipeline">Sin empresas</p>`}</div>`}).join("")}
function setupPipeline(){$$(".company-card[draggable]").forEach(card=>{card.ondragstart=e=>{draggedCompany=card.dataset.company;e.dataTransfer.setData("text/plain",draggedCompany);card.classList.add("dragging-card");document.body.classList.add("dragging")};card.ondragend=()=>{$$(".drop-zone").forEach(z=>z.classList.remove("drag-over"));card.classList.remove("dragging-card");document.body.classList.remove("dragging");draggedCompany=null}});$$(".drop-zone").forEach(z=>{z.ondragover=e=>{e.preventDefault();z.classList.add("drag-over")};z.ondragleave=e=>{if(!z.contains(e.relatedTarget))z.classList.remove("drag-over")};z.ondrop=e=>{e.preventDefault();moveCompany(e.dataTransfer.getData("text/plain")||draggedCompany,z.dataset.status);z.classList.remove("drag-over")}})}
function moveCompany(id,status){const e=state.empresas.find(x=>x.id===id);if(!e||e.estado===status)return;const old=e.estado;e.estado=status;log(`Empresa actualizada: ${e.nombre} pasó de ${old} a ${status}`);scheduleSave();render();toast(`${e.nombre} movida a ${status} 🌸`)}
function filteredEmpresas(){let arr=state.empresas;if(filters.empresas==="sinSeguimiento")arr=arr.filter(e=>!state.seguimientos.some(s=>s.empresa===e.nombre));return arr}
function renderEmpresas(){const q=$("#empresaSearch")?.value?.toLowerCase()||"",list=filteredEmpresas().filter(e=>!q||JSON.stringify(e).toLowerCase().includes(q));$("#empresas").innerHTML=pageHead("Empresas","Empresas",filters.empresas==="sinSeguimiento"?"Empresas sin seguimiento":"CRM de empresas colaboradoras")+`<section class="card table-card"><div class="toolbar">${filters.empresas!=="all"?`<button class="soft-btn" onclick="filters.empresas='all';render()">Filtro Dashboard ×</button>`:""}<input id="empresaSearch" placeholder="Buscar empresa..." oninput="renderEmpresas()" value="${esc(q)}"><button class="primary" onclick="openEmpresa()">Añadir empresa</button><button class="soft-btn" onclick="openImportExcel('empresas')">Importar Excel/CSV</button><button class="soft-btn" onclick="exportExcel('empresas')">Exportar Excel</button><button class="soft-btn" onclick="downloadTemplate('empresas')">Plantilla</button></div><table><thead><tr><th>Empresa</th><th>Sector</th><th>Contacto</th><th>Estado</th><th>Prioridad</th><th></th></tr></thead><tbody>${list.map(e=>`<tr onclick="openEmpresa360('${e.id}')"><td><b>${esc(e.nombre)}</b><br><small>${esc(e.ciudad)} · ${esc(e.isla)}</small></td><td>${esc(e.sector)}</td><td>${esc(e.contacto)}<br><small>${esc(e.telefono)} · ${esc(e.email)}</small></td><td><span class="badge">${esc(e.estado)}</span></td><td>${esc(e.prioridad)}</td><td class="row-actions" onclick="event.stopPropagation()"><button onclick="openEmpresa('${e.id}')">Editar</button><button onclick="delEmpresa('${e.id}')">Eliminar</button></td></tr>`).join("")||`<tr><td colspan="6">No hay empresas.</td></tr>`}</tbody></table></section>`}
function openEmpresa(id=null){const e=state.empresas.find(x=>x.id===id)||{nombre:"",sector:"",subsector:"",ciudad:"Las Palmas",isla:"Gran Canaria",web:"",fuente:"",acepta_practicas:"",tipo_practicas:"",ciclos_recomendados:"",estado:"nueva",prioridad:"media",contacto:"",telefono:"",email:"",notas:""};modal("Empresa",`<form id="empresaForm" class="form-grid"><input name="nombre" value="${esc(e.nombre)}" placeholder="Nombre" required><input name="sector" value="${esc(e.sector)}" placeholder="Sector"><input name="subsector" value="${esc(e.subsector)}" placeholder="Subsector"><input name="ciudad" value="${esc(e.ciudad)}" placeholder="Ciudad"><input name="isla" value="${esc(e.isla)}" placeholder="Isla"><input name="web" value="${esc(e.web)}" placeholder="Web"><input name="contacto" value="${esc(e.contacto)}" placeholder="Contacto"><input name="telefono" value="${esc(e.telefono)}" placeholder="Teléfono"><input name="email" value="${esc(e.email)}" placeholder="Email"><select name="estado">${["nueva","contactada","interesada","convenio","activa","descartada"].map(x=>`<option ${e.estado===x?"selected":""}>${x}</option>`).join("")}</select><select name="prioridad">${["alta","media","baja"].map(x=>`<option ${e.prioridad===x?"selected":""}>${x}</option>`).join("")}</select><input name="fuente" value="${esc(e.fuente)}" placeholder="Fuente"><input name="acepta_practicas" value="${esc(e.acepta_practicas)}" placeholder="Acepta prácticas"><input name="tipo_practicas" value="${esc(e.tipo_practicas)}" placeholder="Tipo prácticas"><input name="ciclos_recomendados" value="${esc(e.ciclos_recomendados)}" placeholder="Ciclos recomendados"><textarea name="notas" placeholder="Notas">${esc(e.notas)}</textarea></form>`,()=>{Object.assign(e,Object.fromEntries(new FormData($("#empresaForm")).entries()));if(!id){e.id=uid();state.empresas.unshift(e)}log(`Empresa guardada: ${e.nombre}`);scheduleSave();closeModal();render()})}
function delEmpresa(id){if(confirm("¿Eliminar empresa?")){state.empresas=state.empresas.filter(e=>e.id!==id);scheduleSave();render()}}
function openEmpresa360(id){const e=state.empresas.find(x=>x.id===id);if(!e)return;const follows=state.seguimientos.filter(s=>s.empresa===e.nombre),convs=state.convenios.filter(c=>c.empresa===e.nombre),alumnos=state.alumnos.filter(a=>a.empresa===e.nombre),docs=state.documentos.filter(d=>d.empresa===e.nombre);modal("Empresa 360",`<section class="empresa360-profile"><aside class="empresa360-side"><div class="empresa360-logo">${esc((e.nombre||"E")[0])}</div><h2>${esc(e.nombre)}</h2><p>${esc(e.sector)}</p><span class="badge">${esc(e.estado)}</span><button class="primary" onclick="openEmpresa('${e.id}')">Editar empresa</button></aside><main class="empresa360-main"><section class="empresa360-grid">${[["Contacto",e.contacto],["Teléfono",e.telefono],["Email",e.email],["Web",e.web],["Ciudad",`${e.ciudad} · ${e.isla}`],["Prioridad",e.prioridad]].map(([b,v])=>`<article><b>${b}</b><span>${esc(v||"Sin dato")}</span></article>`).join("")}</section><section class="empresa360-section"><div class="section-head"><div><p>Seguimiento</p><h3>Interacciones</h3></div></div><div class="list">${follows.map(s=>`<article class="item"><div><b>${esc(s.tipo)} · ${esc(s.fecha)}</b><p>${esc(s.resultado)} · Próxima: ${esc(s.proxima)}</p></div></article>`).join("")||"<p>Sin seguimiento.</p>"}</div></section><section class="empresa360-section"><div class="section-head"><div><p>Alumnos</p><h3>Asignados</h3></div></div><div class="list">${alumnos.map(a=>`<article class="item" onclick="openStudentProfile('${a.id}')"><div><b>${esc(a.nombre)}</b><p>${esc(a.estado)}</p></div><span>Ver</span></article>`).join("")||"<p>Sin alumnos.</p>"}</div></section><section class="empresa360-section"><div class="section-head"><div><p>Convenios</p><h3>Documentación</h3></div></div><div class="list">${convs.map(c=>`<article class="item"><div><b>${esc(c.empresa)}</b><p>${esc(c.inicio)} → ${esc(c.fin)} · ${esc(c.estado)}</p></div></article>`).join("")||"<p>Sin convenios.</p>"}</div></section><section class="empresa360-section"><div class="section-head"><div><p>Documentos</p><h3>Archivos</h3></div></div><div class="list">${docs.map(d=>`<article class="item" onclick="previewAnyFile(state.documentos.find(x=>x.id==='${d.id}').file,'${esc(d.nombre)}')"><div><b>${esc(d.nombre)}</b><p>${esc(d.tipo)} · ${esc(d.estado)}</p></div><span>Ver</span></article>`).join("")||"<p>Sin documentos.</p>"}</div></section></main></section>`,()=>closeModal())}
function filteredAlumnos(){let arr=state.alumnos;if(filters.alumnos==="sinEmpresa")arr=arr.filter(a=>!a.empresa||a.estado==="sin asignar");return arr}
function renderAlumnos(){const list=filteredAlumnos();$("#alumnos").innerHTML=pageHead("Alumnos","Alumnos",filters.alumnos==="sinEmpresa"?"Alumnos sin empresa":"Ficha completa del alumnado")+`<section class="card table-card"><div class="toolbar">${filters.alumnos!=="all"?`<button class="soft-btn" onclick="filters.alumnos='all';render()">Filtro Dashboard ×</button>`:""}<button class="primary" onclick="openAlumno()">Añadir alumno</button><button class="soft-btn" onclick="openImportExcel('alumnos')">Importar Excel/CSV</button><button class="soft-btn" onclick="exportExcel('alumnos')">Exportar Excel</button><button class="soft-btn" onclick="downloadTemplate('alumnos')">Plantilla</button></div><table><thead><tr><th>Alumno</th><th>Contacto</th><th>Empresa</th><th>Estado</th><th>Archivos</th><th></th></tr></thead><tbody>${list.map(a=>`<tr class="student-row" onclick="openStudentProfile('${a.id}')"><td><div class="student-cell"><div class="student-avatar">${a.foto?.path?`<span>${esc((a.nombre||"A")[0])}</span>`:a.foto?.data?`<img src="${a.foto.data}">`:`<span>${esc((a.nombre||"A")[0])}</span>`}</div><div><b>${esc(a.nombre)}</b><br><small>DNI: ${esc(a.dni||"Sin DNI")} · NSS: ${esc(a.nss||"")}</small></div></div></td><td>${esc(a.telefono)}<br><small>${esc(a.email)}</small></td><td>${esc(a.empresa||"Sin empresa")}</td><td><span class="badge">${esc(a.estado)}</span></td><td onclick="event.stopPropagation()"><div class="student-files">${a.foto?`<button onclick="previewAnyFile(state.alumnos.find(x=>x.id==='${a.id}').foto,'Foto')">Foto</button>`:`<span>Sin foto</span>`}${a.curriculum?`<button onclick="previewAnyFile(state.alumnos.find(x=>x.id==='${a.id}').curriculum,'CV')">CV</button>`:`<span>Sin CV</span>`}</div></td><td class="row-actions" onclick="event.stopPropagation()"><button onclick="openAlumno('${a.id}')">Editar</button><button onclick="delAlumno('${a.id}')">Eliminar</button></td></tr>`).join("")||`<tr><td colspan="6">No hay alumnos.</td></tr>`}</tbody></table></section>`}
function openAlumno(id=null){const a=state.alumnos.find(x=>x.id===id)||{nombre:"",dni:"",telefono:"",email:"",direccion:"",nss:"",estado:"sin asignar",empresa:"",inicio:"",fin:"",tutor:"",horas:"",evaluacion:"",notas:"",foto:null,curriculum:null};modal("Alumno",`<form id="alumnoForm" class="form-grid"><div class="student-photo-preview">${a.foto?.data?`<img src="${a.foto.data}">`:"Foto"}</div><input name="nombre" value="${esc(a.nombre)}" placeholder="Nombre" required><input name="dni" value="${esc(a.dni)}" placeholder="DNI / NIE"><input name="telefono" value="${esc(a.telefono)}" placeholder="Teléfono"><input name="email" value="${esc(a.email)}" placeholder="Correo"><input name="direccion" value="${esc(a.direccion)}" placeholder="Dirección"><input name="nss" value="${esc(a.nss)}" placeholder="Nº Seguridad Social"><label class="student-files">Foto<input id="alumnoFoto" type="file" accept="image/*"></label><label class="student-files">Currículum<input id="alumnoCV" type="file" accept=".pdf,.doc,.docx,.jpg,.jpeg,.png,.webp"></label><select name="empresa"><option value="">Sin empresa</option>${state.empresas.map(e=>`<option ${a.empresa===e.nombre?"selected":""}>${esc(e.nombre)}</option>`).join("")}</select><select name="estado">${["sin asignar","propuesta","entrevista","prácticas","finalizado"].map(x=>`<option ${a.estado===x?"selected":""}>${x}</option>`).join("")}</select><input name="inicio" type="date" value="${esc(a.inicio)}"><input name="fin" type="date" value="${esc(a.fin)}"><input name="tutor" value="${esc(a.tutor)}" placeholder="Tutor"><input name="horas" value="${esc(a.horas)}" placeholder="Horas"><input name="evaluacion" value="${esc(a.evaluacion)}" placeholder="Evaluación"><textarea name="notas">${esc(a.notas)}</textarea></form>`,async()=>{Object.assign(a,Object.fromEntries(new FormData($("#alumnoForm")).entries()));const foto=$("#alumnoFoto").files[0],cv=$("#alumnoCV").files[0];if(foto)a.foto=await uploadFile(foto,`alumnos/${safeFileName(a.nombre)}/foto`);if(cv)a.curriculum=await uploadFile(cv,`alumnos/${safeFileName(a.nombre)}/cv`);if(!id){a.id=uid();state.alumnos.unshift(a)}log(`Alumno guardado: ${a.nombre}`);scheduleSave();closeModal();render()})}
function delAlumno(id){if(confirm("¿Eliminar alumno?")){state.alumnos=state.alumnos.filter(a=>a.id!==id);scheduleSave();render()}}
function openStudentProfile(id){const a=state.alumnos.find(x=>x.id===id);if(!a)return;const e=state.empresas.find(x=>x.nombre===a.empresa),c=state.convenios.find(x=>x.empresa===a.empresa),docs=state.documentos.filter(d=>d.alumno===a.nombre||d.empresa===a.empresa),follows=state.seguimientos.filter(s=>s.empresa===a.empresa);modal("Ficha del alumno",`<section class="student-profile"><aside class="student-profile-side"><div class="student-profile-photo">${a.foto?.data?`<img src="${a.foto.data}">`:`<span>${esc((a.nombre||"A")[0])}</span>`}</div><h2>${esc(a.nombre)}</h2><p>${esc(a.estado)}</p><button class="primary" onclick="openAlumno('${a.id}')">Editar ficha</button></aside><main class="student-profile-main"><section class="student-profile-grid">${[["DNI",a.dni],["Teléfono",a.telefono],["Correo",a.email],["Dirección",a.direccion],["NSS",a.nss],["Empresa",a.empresa||"Sin empresa"],["Tutor",a.tutor||e?.contacto],["Inicio",a.inicio||c?.inicio],["Fin",a.fin||c?.fin],["Horas",a.horas],["Evaluación",a.evaluacion]].map(([b,v])=>`<article><b>${b}</b><span>${esc(v||"Sin dato")}</span></article>`).join("")}</section><section class="student-profile-section"><div class="section-head"><div><p>Currículum</p><h3>Vista previa</h3></div></div>${filePreviewHTML(a.curriculum,"cv"+a.id)}</section><section class="student-profile-section"><div class="section-head"><div><p>Documentos</p><h3>Relacionados</h3></div></div><div class="list">${docs.map(d=>`<article class="item" onclick="previewAnyFile(state.documentos.find(x=>x.id==='${d.id}').file,'${esc(d.nombre)}')"><div><b>${esc(d.nombre)}</b><p>${esc(d.tipo)} · ${esc(d.estado)}</p></div><span>Ver</span></article>`).join("")||"<p>No hay documentos asociados.</p>"}</div></section><section class="student-profile-section"><div class="section-head"><div><p>Seguimiento</p><h3>Actividad</h3></div></div><div class="list">${follows.map(s=>`<article class="item"><div><b>${esc(s.tipo)} · ${esc(s.empresa)}</b><p>${esc(s.fecha)} · ${esc(s.resultado||"")}</p></div></article>`).join("")||"<p>Sin seguimientos.</p>"}</div></section></main></section>`,()=>closeModal())}
function renderPracticas(){let list=state.alumnos.filter(a=>a.estado==="prácticas"||a.empresa||a.inicio||a.fin);const f=filters.practicas;list=list.filter(a=>(f.estado==="todas"||a.estado===f.estado)&&(f.empresa==="todas"||a.empresa===f.empresa)&&(!f.alumno||a.nombre.toLowerCase().includes(f.alumno.toLowerCase()))&&(!f.fecha||((!a.inicio||a.inicio<=f.fecha)&&(!a.fin||a.fin>=f.fecha))));$("#practicas").innerHTML=pageHead("Prácticas","Prácticas","Seguimiento operativo de prácticas")+`<section class="kpi-grid">${kpiSimple("Activas",list.filter(a=>practiceStatus(a)==="Activa").length,"green","briefcase")}${kpiSimple("Pendientes",list.filter(a=>practiceStatus(a)==="Pendiente").length,"blue","student")}${kpiSimple("Finalizadas",list.filter(a=>practiceStatus(a).includes("Finalizada")).length,"orange","file")}${kpiSimple("Sin fechas",list.filter(a=>!a.inicio||!a.fin).length,"pink","calendar")}</section><section class="card table-card"><div class="toolbar"><select onchange="filters.practicas.estado=this.value;renderPracticas()">${["todas","sin asignar","propuesta","entrevista","prácticas","finalizado"].map(x=>`<option ${f.estado===x?"selected":""}>${x}</option>`).join("")}</select><select onchange="filters.practicas.empresa=this.value;renderPracticas()"><option value="todas">Todas las empresas</option>${state.empresas.map(e=>`<option value="${esc(e.nombre)}" ${f.empresa===e.nombre?"selected":""}>${esc(e.nombre)}</option>`).join("")}</select><input placeholder="Buscar alumno..." value="${esc(f.alumno)}" oninput="filters.practicas.alumno=this.value;renderPracticas()"><input type="date" value="${esc(f.fecha)}" onchange="filters.practicas.fecha=this.value;renderPracticas()"><button class="primary" onclick="openAlumno()">Añadir práctica</button></div><div class="practice-grid">${list.map(practiceCard).join("")||`<article class="empty-day"><b>No hay prácticas.</b><p>Asigna empresa y fechas a un alumno.</p><button class="primary" onclick="openAlumno()">Crear práctica</button></article>`}</div></section>`}
function kpiSimple(l,v,color,icon){return `<article class="kpi card"><div class="kpi-icon ${color}">${icons[icon]}</div><strong>${v}</strong><span>${l}</span></article>`} function practiceStatus(a){if(a.estado==="finalizado")return"Finalizada";if(!a.inicio||!a.fin)return"Sin fechas";if(today()<a.inicio)return"Pendiente";if(today()>a.fin)return"Finalizada";return"Activa"} function progress(a){if(!a.inicio||!a.fin)return 0;const s=new Date(a.inicio),e=new Date(a.fin),n=new Date();if(n<=s)return 0;if(n>=e)return 100;return Math.round((n-s)/(e-s)*100)}
function practiceCard(a){const e=state.empresas.find(x=>x.nombre===a.empresa),c=state.convenios.find(x=>x.empresa===a.empresa),docs=state.documentos.filter(d=>d.alumno===a.nombre||d.empresa===a.empresa),p=progress(a);return `<article class="practice-card"><header><div class="student-avatar"><span>${esc((a.nombre||"A")[0])}</span></div><div><h3>${esc(a.nombre)}</h3><p>${esc(a.empresa||"Sin empresa")} · ${practiceStatus(a)}</p></div><span class="badge">${esc(a.estado)}</span></header><div class="practice-data">${[["DNI",a.dni],["Teléfono",a.telefono],["Tutor",a.tutor||e?.contacto],["Convenio",c?.estado||"Sin convenio"],["Inicio",a.inicio],["Fin",a.fin],["Horas",a.horas],["Documentos",docs.length]].map(([b,v])=>`<article><b>${b}</b><span>${esc(v||"Sin dato")}</span></article>`).join("")}</div><div class="practice-progress"><div><span>Progreso</span><b>${p}%</b></div><i><em style="width:${p}%"></em></i></div><div class="practice-actions"><button onclick="openStudentProfile('${a.id}')">Ver expediente</button><button onclick="openAlumno('${a.id}')">Editar</button><button onclick="selectedDate='${esc(a.inicio||today())}';show('agenda')">Agenda</button></div></article>`}
function renderConvenios(){let list=filters.convenios==="pendientes"?state.convenios.filter(c=>c.estado!=="firmado"&&c.estado!=="completo"):state.convenios;$("#convenios").innerHTML=pageHead("Convenios","Convenios",filters.convenios==="pendientes"?"Pendientes":"Borradores, firmas y anexos")+`<section class="grid-2"><div class="card table-card"><div class="toolbar">${filters.convenios!=="all"?`<button class="soft-btn" onclick="filters.convenios='all';render()">Filtro ×</button>`:""}<button class="primary" onclick="openConvenio()">Nuevo convenio</button><button class="soft-btn" onclick="show('documentos')">Archivo documental</button></div><table><thead><tr><th>Empresa</th><th>Fechas</th><th>Estado</th><th>Anexos</th><th></th></tr></thead><tbody>${list.map(c=>`<tr><td><b>${esc(c.empresa)}</b><br><small>${esc(c.centro)}</small></td><td>${esc(c.inicio)} → ${esc(c.fin)}</td><td><span class="badge">${esc(c.estado)}</span></td><td>${(c.anexos||[]).length}</td><td class="row-actions"><button onclick="openConvenio('${c.id}')">Editar</button><button onclick="attachDoc('${c.id}')">Anexar</button><button onclick="delConvenio('${c.id}')">Eliminar</button></td></tr>`).join("")||`<tr><td colspan="5">No hay convenios.</td></tr>`}</tbody></table></div><div class="card table-card"><div class="section-head"><div><p>Estado documental</p><h3>Checklist</h3></div></div><div class="list">${list.map(c=>`<article class="item"><div><b>${esc(c.empresa)}</b><p>${(c.anexos||[]).length>=3?"Completo":(c.anexos||[]).length?"Incompleto":"Pendiente"}</p></div><span>${esc(c.estado)}</span></article>`).join("")||"<p>No hay convenios.</p>"}</div></div></section>`}
function openConvenio(id=null){const c=state.convenios.find(x=>x.id===id)||{empresa:"",centro:"Centro educativo",inicio:today(),fin:datePlus(90),tutorEmpresa:"",tutorCentro:"",estado:"pendiente",anexos:[]};modal("Convenio",`<form id="convForm" class="form-grid"><select name="empresa">${state.empresas.map(e=>`<option ${c.empresa===e.nombre?"selected":""}>${esc(e.nombre)}</option>`).join("")}</select><input name="centro" value="${esc(c.centro)}"><input name="inicio" type="date" value="${esc(c.inicio)}"><input name="fin" type="date" value="${esc(c.fin)}"><input name="tutorEmpresa" value="${esc(c.tutorEmpresa)}" placeholder="Tutor empresa"><input name="tutorCentro" value="${esc(c.tutorCentro)}" placeholder="Tutor centro"><select name="estado">${["pendiente","incompleto","completo","vencido","firmado","enviado"].map(x=>`<option ${c.estado===x?"selected":""}>${x}</option>`).join("")}</select></form>`,()=>{Object.assign(c,Object.fromEntries(new FormData($("#convForm")).entries()));if(!id){c.id=uid();c.anexos=[];state.convenios.unshift(c)}log(`Convenio guardado: ${c.empresa}`);scheduleSave();closeModal();render()})}
function attachDoc(id){const c=state.convenios.find(x=>x.id===id);modal("Anexar documento",`<select id="docToAttach">${state.documentos.map(d=>`<option value="${d.id}">${esc(d.nombre)} · ${esc(d.tipo)}</option>`).join("")}</select><p>Si no aparece el documento, súbelo primero en Documentos.</p>`,()=>{const did=$("#docToAttach").value;c.anexos=c.anexos||[];if(did&&!c.anexos.includes(did))c.anexos.push(did);scheduleSave();closeModal();render()})} function delConvenio(id){if(confirm("¿Eliminar convenio?")){state.convenios=state.convenios.filter(c=>c.id!==id);scheduleSave();render()}}
function renderExpedientes(){let list=filters.expedientes==="practicasActivas"?state.alumnos.filter(a=>a.estado==="prácticas"):state.alumnos;$("#expedientes").innerHTML=pageHead("Expedientes","Expedientes","Vista completa por alumno")+`${filters.expedientes!=="all"?`<button class="soft-btn" onclick="filters.expedientes='all';render()">Filtro ×</button>`:""}<section class="grid-2">${list.map(a=>{const e=state.empresas.find(x=>x.nombre===a.empresa),c=state.convenios.find(x=>x.empresa===a.empresa),docs=state.documentos.filter(d=>d.alumno===a.nombre||d.empresa===a.empresa);return `<article class="card table-card"><div class="section-head"><div><p>Expediente</p><h3>${esc(a.nombre)}</h3></div><span class="badge">${esc(a.estado)}</span></div><div class="grid-2"><div><b>Empresa</b><p>${esc(a.empresa||"Sin empresa")}</p><b>DNI</b><p>${esc(a.dni||"Sin dato")}</p><b>Contacto</b><p>${esc(e?.contacto||"")}</p><b>Fechas</b><p>${esc(a.inicio||"")} → ${esc(a.fin||"")}</p></div><div><b>Convenio</b><p>${esc(c?.estado||"Sin convenio")}</p><b>Documentos</b><p>${docs.length} asociados</p><b>Próxima acción</b><p>${esc(state.seguimientos.find(s=>s.empresa===a.empresa)?.proxima||"Sin acción")}</p></div></div><button class="primary" onclick="openStudentProfile('${a.id}')">Ver ficha</button></article>`}).join("")||"<p>No hay expedientes.</p>"}</section>`}
function renderDocumentos(){const q=$("#docSearch")?.value?.toLowerCase()||"",t=$("#docTypeFilter")?.value||"Todos";const docs=state.documentos.filter(d=>(activeFolder==="all"||(!d.carpeta&&activeFolder==="sin")||d.carpeta===activeFolder)&&(!q||JSON.stringify(d).toLowerCase().includes(q))&&(t==="Todos"||d.tipo===t));$("#documentos").innerHTML=pageHead("Documentos","Documentos","Archivo privado con carpetas")+`<section class="doc-layout"><aside class="card table-card folders"><div class="section-head"><div><p>Carpetas</p><h3>Archivo</h3></div></div><form class="form-grid" onsubmit="addFolder(event)"><input id="folderName" placeholder="Nueva carpeta" required><button class="primary">Crear</button></form><div class="folder-list">${state.carpetas.map(f=>`<div class="folder ${activeFolder===f.id?"active":""}" onclick="activeFolder='${f.id}';renderDocumentos()"><span>📁 ${esc(f.nombre)}</span><div class="folder-actions" onclick="event.stopPropagation()"><b>${state.documentos.filter(d=>f.id==="all"||(!d.carpeta&&f.id==="sin")||d.carpeta===f.id).length}</b>${!["all","sin"].includes(f.id)?`<button onclick="editFolder('${f.id}')">✎</button><button onclick="deleteFolder('${f.id}')">×</button>`:""}</div></div>`).join("")}</div></aside><main><section class="card table-card"><div class="section-head"><div><p>Subir</p><h3>Nuevo documento privado</h3></div></div><form class="form-grid" onsubmit="addDoc(event)"><input id="docNombre" placeholder="Nombre visible"><select id="docCarpeta">${state.carpetas.filter(f=>!["all","sin"].includes(f.id)).map(f=>`<option value="${f.id}">${esc(f.nombre)}</option>`).join("")}</select><select id="docTipo"><option>convenio firmado</option><option>DNI/NIF</option><option>seguro</option><option>acuerdo formativo</option><option>evaluación</option><option>anexo de prácticas</option><option>cv</option><option>otro</option></select><select id="docEmpresa"><option value="">Sin empresa</option>${state.empresas.map(e=>`<option>${esc(e.nombre)}</option>`).join("")}</select><select id="docAlumno"><option value="">Sin alumno</option>${state.alumnos.map(a=>`<option>${esc(a.nombre)}</option>`).join("")}</select><select id="docEstado"><option>pendiente</option><option>para enviar</option><option>enviado</option><option>firmado</option><option>caducado</option></select><input id="docFecha" type="date" value="${today()}"><input id="docUser" placeholder="Subido por"><label>Archivo<input id="docFile" type="file" required></label><textarea id="docNotas" placeholder="Notas"></textarea><button class="primary">Guardar documento</button></form></section><section class="card table-card" style="margin-top:18px"><div class="toolbar"><input id="docSearch" placeholder="Buscar..." oninput="renderDocumentos()" value="${esc(q)}"><select id="docTypeFilter" onchange="renderDocumentos()"><option>Todos</option><option>convenio firmado</option><option>DNI/NIF</option><option>seguro</option><option>cv</option></select></div><div class="doc-grid">${docs.map(docCard).join("")||"<p>No hay documentos.</p>"}</div></section></main></section>`;const sel=$("#docTypeFilter");if(sel)sel.value=t}
function addFolder(ev){ev.preventDefault();state.carpetas.push({id:uid(),nombre:$("#folderName").value});log(`Carpeta creada: ${$("#folderName").value}`);scheduleSave();render()} function editFolder(id){const f=state.carpetas.find(x=>x.id===id);modal("Modificar carpeta",`<form id="folderForm" class="form-grid"><input id="editFolderName" value="${esc(f.nombre)}" required></form>`,()=>{f.nombre=$("#editFolderName").value;log(`Carpeta modificada: ${f.nombre}`);scheduleSave();closeModal();render()})} function deleteFolder(id){const f=state.carpetas.find(x=>x.id===id);if(!f||["all","sin"].includes(id))return;if(confirm("Eliminar carpeta? Los documentos pasarán a Sin carpeta.")){state.documentos.forEach(d=>{if(d.carpeta===id)d.carpeta=""});state.carpetas=state.carpetas.filter(x=>x.id!==id);activeFolder="all";log(`Carpeta eliminada: ${f.nombre}`);scheduleSave();render()}}
async function addDoc(ev){ev.preventDefault();const raw=$("#docFile").files[0];if(!raw)return;const empresa=$("#docEmpresa").value,alumno=$("#docAlumno").value,folder=empresa?`empresas/${safeFileName(empresa)}`:alumno?`alumnos/${safeFileName(alumno)}/documentos`:"documentos";const file=await uploadFile(raw,folder);if(!file)return;state.documentos.unshift({id:uid(),nombre:$("#docNombre").value||raw.name,tipo:$("#docTipo").value,empresa,alumno,estado:$("#docEstado").value,fecha:$("#docFecha").value,subidoPor:$("#docUser").value,notas:$("#docNotas").value,carpeta:$("#docCarpeta").value,file});log(`Documento subido: ${raw.name}`);scheduleSave();render();toast("Documento privado guardado 🌸")}
function docCard(d){return `<article class="card doc-card"><h3>${esc(d.nombre)}</h3><p>${esc(d.tipo)} · ${esc(d.estado)}</p><p>${esc(d.empresa||d.alumno||"General")} · ${esc(d.fecha)}</p><p>${esc(d.notas||"")}</p><div class="doc-actions"><button onclick="previewAnyFile(state.documentos.find(x=>x.id==='${d.id}').file,'${esc(d.nombre)}')">Previsualizar</button><button onclick="replaceDoc('${d.id}')">Reemplazar</button><button onclick="delDoc('${d.id}')">Eliminar</button></div></article>`} function replaceDoc(id){const inp=document.createElement("input");inp.type="file";inp.onchange=async()=>{const d=state.documentos.find(x=>x.id===id);const file=await uploadFile(inp.files[0],"documentos");if(file){d.file=file;d.nombre=file.name;d.fecha=today();scheduleSave();render()}};inp.click()} function delDoc(id){if(confirm("¿Eliminar documento?")){state.documentos=state.documentos.filter(d=>d.id!==id);scheduleSave();render()}}
async function filePreviewHTML(file,id="x"){if(!file)return `<div class="student-cv-empty">No hay archivo adjunto.</div>`;if(file.path){const pid=`pv-${id}-${Math.floor(Math.random()*9999)}`;setTimeout(()=>renderSigned(file,pid),50);return `<div id="${pid}" class="student-cv-empty"><b>Preparando vista privada...</b><span>Generando enlace temporal seguro.</span></div>`}return `<div class="student-cv-empty"><b>${esc(file.name||"Archivo")}</b><span>Archivo heredado sin Storage.</span></div>`}
async function renderSigned(file,id){const el=$("#"+id);if(!el)return;const url=await signedUrl(file.path),n=file.name||"archivo",t=file.type||"",pdf=t.includes("pdf")||n.endsWith(".pdf"),img=t.includes("image")||/\.(png|jpg|jpeg|webp)$/i.test(n);if(!url){el.innerHTML="<b>No se pudo abrir.</b><span>Revisa policies.</span>";return}if(pdf)el.outerHTML=`<div class="student-cv-preview"><iframe src="${url}"></iframe></div><div class="student-cv-actions"><a href="${url}" target="_blank">Abrir temporal</a><a href="${url}" download="${esc(n)}">Descargar</a></div>`;else if(img)el.outerHTML=`<div class="student-cv-image"><img src="${url}"></div><div class="student-cv-actions"><a href="${url}" target="_blank">Abrir temporal</a><a href="${url}" download="${esc(n)}">Descargar</a></div>`;else el.outerHTML=`<div class="student-cv-empty"><b>${esc(n)}</b><span>Archivo privado.</span></div><div class="student-cv-actions"><a href="${url}" target="_blank">Abrir/descargar temporal</a></div>`}
async function previewAnyFile(file,title="Documento"){modal("Previsualizar documento",`<section><h2>${esc(title)}</h2><div id="previewAsync">Cargando...</div></section>`,()=>closeModal());$("#previewAsync").outerHTML=await filePreviewHTML(file,"modal")}
function renderSeguimiento(){let list=filters.seguimiento==="llamadas"?state.seguimientos.filter(s=>s.tipo==="llamada"):filters.seguimiento==="reuniones"?state.seguimientos.filter(s=>s.tipo==="reunión"):state.seguimientos;$("#seguimiento").innerHTML=pageHead("Seguimiento","Seguimiento",filters.seguimiento!=="all"?`Filtro: ${filters.seguimiento}`:"Llamadas, emails, visitas y reuniones")+`<section class="grid-2"><div class="card table-card"><div class="toolbar">${filters.seguimiento!=="all"?`<button class="soft-btn" onclick="filters.seguimiento='all';render()">Filtro ×</button>`:""}</div><form class="form-grid" onsubmit="addSeguimiento(event)"><input id="segFecha" type="date" value="${today()}"><select id="segEmpresa">${state.empresas.map(e=>`<option>${esc(e.nombre)}</option>`).join("")}</select><select id="segTipo"><option>llamada</option><option>email</option><option>visita</option><option>reunión</option><option>LinkedIn</option></select><input id="segResultado" placeholder="Resultado"><input id="segProxima" placeholder="Próxima acción"><input id="segFechaProx" type="date" value="${datePlus(7)}"><input id="segResponsable" placeholder="Responsable"><button class="primary">Registrar</button></form></div><div class="card table-card"><div class="list">${list.map(s=>`<article class="item"><div><b>${esc(s.tipo)} · ${esc(s.empresa)}</b><p>${esc(s.resultado)} · Próxima: ${esc(s.proxima)}</p></div><span>${esc(s.fecha)}</span></article>`).join("")||"<p>No hay seguimientos.</p>"}</div></div></section>`} function addSeguimiento(ev){ev.preventDefault();state.seguimientos.unshift({id:uid(),fecha:$("#segFecha").value,empresa:$("#segEmpresa").value,tipo:$("#segTipo").value,resultado:$("#segResultado").value,proxima:$("#segProxima").value,fechaProxima:$("#segFechaProx").value,responsable:$("#segResponsable").value});log(`Seguimiento registrado: ${$("#segEmpresa").value}`);scheduleSave();render()}
function renderEmails(){$("#emails").innerHTML=pageHead("Emails","Emails","Plantillas reutilizables")+`<section class="grid-2"><div class="card table-card"><form class="form-grid" onsubmit="addEmail(event)"><input id="emailNombre" placeholder="Nombre plantilla" required><input id="emailAsunto" placeholder="Asunto"><textarea id="emailCuerpo" placeholder="Cuerpo"></textarea><button class="primary">Guardar plantilla</button></form></div><div class="card table-card"><div class="list">${state.emails.map(t=>`<article class="item"><div><b>${esc(t.nombre)}</b><p>${esc(t.asunto)}</p></div><div class="row-actions"><button onclick="copyEmail('${t.id}')">Copiar</button><button onclick="delEmail('${t.id}')">Eliminar</button></div></article>`).join("")||"<p>Sin plantillas.</p>"}</div></div></section>`} function addEmail(ev){ev.preventDefault();state.emails.unshift({id:uid(),nombre:$("#emailNombre").value,asunto:$("#emailAsunto").value,cuerpo:$("#emailCuerpo").value});scheduleSave();render()} function copyEmail(id){const t=state.emails.find(x=>x.id===id);navigator.clipboard.writeText(`Asunto: ${t.asunto}\n\n${t.cuerpo}`);toast("Email copiado")} function delEmail(id){state.emails=state.emails.filter(e=>e.id!==id);scheduleSave();render()}
function dayEvents(date){const ev=[];state.seguimientos.forEach(s=>{if(s.fecha===date||s.fechaProxima===date)ev.push({kind:"Seguimiento",title:s.proxima||s.resultado||s.tipo,sub:`${s.empresa} · ${s.tipo}`,view:"seguimiento"})});state.convenios.forEach(c=>{if(c.inicio===date||c.fin===date)ev.push({kind:c.inicio===date?"Inicio convenio":"Fin convenio",title:c.empresa,sub:c.estado,view:"convenios"})});state.alumnos.forEach(a=>{if(a.inicio===date||a.fin===date)ev.push({kind:a.inicio===date?"Inicio prácticas":"Fin prácticas",title:a.nombre,sub:a.empresa||"Sin empresa",view:"practicas"})});state.documentos.forEach(d=>{if(d.fecha===date)ev.push({kind:"Documento",title:d.nombre,sub:`${d.tipo} · ${d.estado}`,view:"documentos"})});return ev}
function miniCalendar(sel=selectedDate){const base=new Date((sel||today())+"T12:00:00"),y=base.getFullYear(),m=base.getMonth(),first=(new Date(y,m,1).getDay()+6)%7,last=new Date(y,m+1,0).getDate(),prefix=`${y}-${String(m+1).padStart(2,"0")}`;let cells="";for(let i=0;i<first;i++)cells+=`<span class="day empty"></span>`;for(let d=1;d<=last;d++){const date=`${prefix}-${String(d).padStart(2,"0")}`,count=dayEvents(date).length;cells+=`<button class="day ${count?"has":""} ${date===sel?"selected":""}" onclick="selectedDate='${date}';show('agenda')"><span>${d}</span>${count?`<b>${count}</b>`:""}</button>`}return `<div class="calendar-weekdays"><span>L</span><span>M</span><span>X</span><span>J</span><span>V</span><span>S</span><span>D</span></div><div class="calendar-grid">${cells}</div>`}
function renderAgenda(){const ev=dayEvents(selectedDate),formatted=new Date(selectedDate+"T12:00:00").toLocaleDateString("es-ES",{weekday:"long",day:"numeric",month:"long",year:"numeric"});$("#agenda").innerHTML=pageHead("Agenda","Próximas acciones","Calendario mensual con detalle diario")+`<section class="grid-2"><div class="card table-card"><div class="section-head"><div><p>Calendario</p><h3>Selecciona un día</h3></div><button class="soft-btn" onclick="selectedDate=today();renderAgenda()">Hoy</button></div>${miniCalendar(selectedDate)}</div><div class="card table-card"><div class="section-head"><div><p>Día seleccionado</p><h3>${esc(formatted)}</h3></div><button class="soft-btn" onclick="quickEvent('${selectedDate}')">Añadir pendiente</button></div><div class="day-summary"><article><b>${ev.length}</b><span>Pendientes</span></article><article><b>${ev.filter(e=>e.kind==='Seguimiento').length}</b><span>Seguimientos</span></article><article><b>${ev.filter(e=>e.kind.includes('convenio')).length}</b><span>Convenios</span></article></div><div class="list">${ev.length?ev.map(e=>`<article class="item" onclick="show('${e.view}')"><div><b>${esc(e.title)}</b><p>${esc(e.kind)} · ${esc(e.sub)}</p></div><span>Ir</span></article>`).join(""):`<article class="empty-day"><b>No hay tareas ni pendientes este día.</b><p>Puedes crear un seguimiento, llamada, reunión o tarea.</p><button class="primary" onclick="quickEvent('${selectedDate}')">Crear pendiente</button></article>`}</div></div></section>`}
function actionItem(s){return `<article class="item" onclick="selectedDate='${esc(s.fechaProxima)}';show('agenda')"><div><b>${esc(s.proxima||s.resultado)}</b><p>${esc(s.empresa)} · ${esc(s.tipo)}</p></div><span>${esc(s.fechaProxima)}</span></article>`} function quickEvent(date){modal("Añadir pendiente",`<form id="quickForm" class="form-grid"><input id="qFecha" type="date" value="${esc(date)}"><select id="qEmpresa">${state.empresas.map(e=>`<option>${esc(e.nombre)}</option>`).join("")}</select><select id="qTipo"><option>llamada</option><option>email</option><option>visita</option><option>reunión</option><option>tarea</option></select><input id="qResultado" placeholder="Nota"><input id="qProxima" placeholder="Tarea / próxima acción" required><input id="qResponsable" placeholder="Responsable"></form>`,()=>{state.seguimientos.unshift({id:uid(),fecha:$("#qFecha").value,empresa:$("#qEmpresa").value,tipo:$("#qTipo").value,resultado:$("#qResultado").value,proxima:$("#qProxima").value,fechaProxima:$("#qFecha").value,responsable:$("#qResponsable").value});selectedDate=$("#qFecha").value;log(`Pendiente añadido: ${$("#qProxima").value}`);scheduleSave();closeModal();render()})}
function renderReportes(){const group=(arr,fn)=>arr.reduce((a,x)=>{const k=fn(x)||"Sin dato";a[k]=(a[k]||0)+1;return a},{});$("#reportes").innerHTML=pageHead("Reportes","Reportes","Estadísticas y exportación")+`<section class="kpi-grid">${kpiSimple("Empresas",state.empresas.length,"pink","building")}${kpiSimple("Alumnos",state.alumnos.length,"blue","student")}${kpiSimple("Convenios",state.convenios.length,"orange","file")}${kpiSimple("Documentos",state.documentos.length,"green","archive")}</section><section class="report-grid"><div class="card table-card"><h3>Empresas por sector</h3>${bars(group(state.empresas,e=>e.sector))}</div><div class="card table-card"><h3>Estados CRM</h3>${bars(group(state.empresas,e=>e.estado))}</div><div class="card table-card"><h3>Convenios</h3>${bars(group(state.convenios,c=>c.estado))}</div><div class="card table-card"><h3>Alumnos</h3>${bars(group(state.alumnos,a=>a.estado))}</div><div class="card table-card"><button class="primary" onclick="exportCSV()">Exportar CSV</button><button class="soft-btn" onclick="window.print()">Exportar PDF</button></div></section>`} function bars(obj){const max=Math.max(1,...Object.values(obj));return Object.entries(obj).map(([k,v])=>`<div class="bar-row"><span>${esc(k)}</span><div class="bar"><i style="width:${v/max*100}%"></i></div><b>${v}</b></div>`).join("")||"<p>Sin datos.</p>"} function exportCSV(){exportExcel("empresas")}
function renderAjustes(){$("#ajustes").innerHTML=pageHead("Ajustes","Ajustes","Cuenta, Supabase y mantenimiento")+`<section class="grid-2"><div class="card table-card"><h3>Cuenta privada</h3><p><b>${esc(user?.email||"")}</b></p><div class="settings-row"><button class="primary" onclick="loadAll().then(render)">Recargar mis datos</button><button class="soft-btn" onclick="logout()">Cerrar sesión</button></div></div><div class="card table-card"><h3>Supabase 5.0</h3><p>Ejecuta este SQL una vez en Supabase para crear tablas privadas, RLS y Storage.</p><button class="primary" onclick="downloadSchema()">Descargar SQL completo</button></div><div class="card table-card"><h3>Backup opcional</h3><button class="primary" onclick="downloadBackup()">Descargar JSON</button><label class="soft-btn">Restaurar JSON<input type="file" onchange="restoreBackup(event)" hidden></label></div></section>`}
function downloadSchema(){const sql=`-- Bloom CRM 5.0 esquema privado\ncreate extension if not exists pgcrypto;\n\n${Object.values(TABLES).map(t=>`create table if not exists ${t} (id text primary key, owner_id uuid not null references auth.users(id) on delete cascade, nombre text, empresa text, sector text, estado text, tipo text, fecha date, fecha_proxima date, carpeta text, data jsonb not null default '{}'::jsonb, created_at timestamptz default now(), updated_at timestamptz default now());\nalter table ${t} enable row level security;\ndrop policy if exists "owner select" on ${t}; drop policy if exists "owner insert" on ${t}; drop policy if exists "owner update" on ${t}; drop policy if exists "owner delete" on ${t};\ncreate policy "owner select" on ${t} for select to authenticated using (owner_id = auth.uid());\ncreate policy "owner insert" on ${t} for insert to authenticated with check (owner_id = auth.uid());\ncreate policy "owner update" on ${t} for update to authenticated using (owner_id = auth.uid()) with check (owner_id = auth.uid());\ncreate policy "owner delete" on ${t} for delete to authenticated using (owner_id = auth.uid());`).join("\n")}\ninsert into storage.buckets (id,name,public) values ('${STORAGE_BUCKET}','${STORAGE_BUCKET}',false) on conflict (id) do update set public=false;\ndrop policy if exists "private read documents" on storage.objects;drop policy if exists "private upload documents" on storage.objects;drop policy if exists "private update documents" on storage.objects;drop policy if exists "private delete documents" on storage.objects;\ncreate policy "private read documents" on storage.objects for select to authenticated using (bucket_id='${STORAGE_BUCKET}' and (storage.foldername(name))[1]=auth.uid()::text);\ncreate policy "private upload documents" on storage.objects for insert to authenticated with check (bucket_id='${STORAGE_BUCKET}' and (storage.foldername(name))[1]=auth.uid()::text);\ncreate policy "private update documents" on storage.objects for update to authenticated using (bucket_id='${STORAGE_BUCKET}' and (storage.foldername(name))[1]=auth.uid()::text) with check (bucket_id='${STORAGE_BUCKET}' and (storage.foldername(name))[1]=auth.uid()::text);\ncreate policy "private delete documents" on storage.objects for delete to authenticated using (bucket_id='${STORAGE_BUCKET}' and (storage.foldername(name))[1]=auth.uid()::text);`;const a=document.createElement("a");a.href=URL.createObjectURL(new Blob([sql],{type:"text/sql"}));a.download="bloom-crm-5-schema.sql";a.click()}
function modal(title,body,onSave){const m=$("#modal");m.innerHTML=`<div class="modal-body"><h2>${title}</h2>${body}<div class="modal-actions"><button class="soft-btn" onclick="closeModal()">Cerrar</button><button class="primary" id="modalSave">Guardar</button></div></div>`;m.showModal();$("#modalSave").onclick=onSave} function closeModal(){$("#modal").close()}
function globalSearch(){const q=$("#globalSearch").value.toLowerCase(),box=$("#searchResults");if(!q){box.classList.add("hidden");return}const res=[...state.empresas.map(x=>({t:"Empresa",n:x.nombre,v:"empresas"})),...state.alumnos.map(x=>({t:"Alumno",n:x.nombre,v:"alumnos"})),...state.documentos.map(x=>({t:"Documento",n:x.nombre,v:"documentos"})),...state.convenios.map(x=>({t:"Convenio",n:x.empresa,v:"convenios"}))].filter(r=>r.n?.toLowerCase().includes(q));box.classList.remove("hidden");box.innerHTML=res.slice(0,8).map(r=>`<article class="item" onclick="show('${r.v}');$('#globalSearch').value='';globalSearch()"><div><b>${esc(r.n)}</b><p>${r.t}</p></div></article>`).join("")||"<p>Sin resultados.</p>"}
function buildNotifications(){const list=[];state.empresas.filter(e=>!state.seguimientos.some(s=>s.empresa===e.nombre)).forEach(e=>list.push({h:`${e.nombre} sin seguimiento`,p:"No tiene interacción registrada.",v:"empresas"}));state.convenios.filter(c=>c.estado!=="firmado"&&c.estado!=="completo").forEach(c=>list.push({h:`Convenio pendiente · ${c.empresa}`,p:`Estado: ${c.estado}`,v:"convenios"}));state.alumnos.filter(a=>!a.empresa).forEach(a=>list.push({h:`${a.nombre} sin empresa`,p:"Pendiente de asignación.",v:"alumnos"}));return list} function renderNotifications(){const n=buildNotifications();$("#alertCount").textContent=n.length;$("#drawerList").innerHTML=n.length?n.map(x=>`<article class="notification" onclick="show('${x.v}');closeDrawer()"><b>${esc(x.h)}</b><p>${esc(x.p)}</p></article>`).join(""):`<article class="notification"><b>Todo tranquilo</b><p>No hay revisiones urgentes.</p></article>`} function openDrawer(){renderNotifications();$("#drawer").classList.add("open");$("#overlay").classList.add("open")} function closeDrawer(){$("#drawer").classList.remove("open");$("#overlay").classList.remove("open")}
function openActivityTarget(text){const l=String(text).toLowerCase(),e=state.empresas.find(e=>l.includes(e.nombre.toLowerCase())),a=state.alumnos.find(a=>l.includes(a.nombre.toLowerCase()));if(e)return openEmpresa360(e.id);if(a)return openStudentProfile(a.id);show("dashboard")}
function normKey(k){return String(k||"").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/[^a-z0-9]+/g,"_").replace(/^_+|_+$/g,"")} function rowVal(row,keys){const n={};Object.entries(row||{}).forEach(([k,v])=>n[normKey(k)]=v);for(const k of keys){const v=n[normKey(k)];if(v!==undefined&&v!==null&&String(v).trim()!=="")return String(v).trim()}return""}
async function readExcel(file){const ext=file.name.split(".").pop().toLowerCase();if(ext==="csv")return parseCSV(await file.text());if(!window.XLSX)throw Error("No se cargó lector Excel");const wb=XLSX.read(await file.arrayBuffer(),{type:"array"}),sh=wb.Sheets[wb.SheetNames[0]];return XLSX.utils.sheet_to_json(sh,{defval:""})}
function parseCSV(text){const lines=String(text).replace(/^\uFEFF/,"").split(/\r?\n/).filter(Boolean);if(!lines.length)return[];const parse=line=>{const out=[];let cur="",q=false;for(let i=0;i<line.length;i++){const ch=line[i];if(ch=='"'&&line[i+1]=='"'){cur+='"';i++;continue}if(ch=='"'){q=!q;continue}if(ch===","&&!q){out.push(cur);cur="";continue}cur+=ch}out.push(cur);return out.map(x=>x.trim())};const h=parse(lines[0]);return lines.slice(1).map(line=>{const v=parse(line),o={};h.forEach((x,i)=>o[x]=v[i]||"");return o})}
function mapEmpresa(r){return{id:uid(),nombre:rowVal(r,["nombre_empresa","empresa","nombre"]),sector:rowVal(r,["sector"]),subsector:rowVal(r,["subsector"]),ciudad:rowVal(r,["ciudad"])||"Las Palmas",isla:rowVal(r,["isla"])||"Gran Canaria",web:rowVal(r,["web"]),fuente:rowVal(r,["fuente"]),acepta_practicas:rowVal(r,["acepta_practicas","acepta"]),tipo_practicas:rowVal(r,["tipo_practicas","tipo"]),ciclos_recomendados:rowVal(r,["ciclos_recomendados","ciclos"]),contacto:rowVal(r,["contacto_nombre","contacto"]),email:rowVal(r,["contacto_email","email","correo"]),telefono:rowVal(r,["contacto_telefono","telefono"]),estado:rowVal(r,["estado_crm","estado"])||"nueva",prioridad:rowVal(r,["prioridad"])||"media",notas:rowVal(r,["notas"])}}
function mapAlumno(r){return{id:uid(),nombre:rowVal(r,["nombre","alumno"]),dni:rowVal(r,["dni","nif","nie"]),telefono:rowVal(r,["telefono"]),email:rowVal(r,["email","correo"]),direccion:rowVal(r,["direccion"]),nss:rowVal(r,["nss","seguridad_social"]),estado:rowVal(r,["estado"])||"sin asignar",empresa:rowVal(r,["empresa"]),inicio:rowVal(r,["inicio","fecha_inicio"]),fin:rowVal(r,["fin","fecha_fin"]),tutor:rowVal(r,["tutor"]),horas:rowVal(r,["horas"]),evaluacion:rowVal(r,["evaluacion"]),notas:rowVal(r,["notas"]),foto:null,curriculum:null}}
let pendingImport={type:"empresas",rows:[]};function openImportExcel(type){pendingImport={type,rows:[]};modal(type==="empresas"?"Importar empresas":"Importar alumnos",`<section class="import-panel"><p>Sube .xlsx, .xls o .csv.</p><div class="import-actions"><label class="import-file-label">Seleccionar archivo<input id="importFile" type="file" accept=".xlsx,.xls,.csv"></label><button type="button" class="soft-btn" onclick="downloadTemplate('${type}')">Plantilla</button></div><label><input id="updateExisting" type="checkbox" checked> Actualizar si el nombre coincide</label><div id="importPreview" class="import-preview"><p>Selecciona un archivo.</p></div></section>`,()=>confirmImport());$("#importFile").onchange=async e=>{const raw=await readExcel(e.target.files[0]);pendingImport.rows=raw.map(type==="empresas"?mapEmpresa:mapAlumno).filter(x=>x.nombre);$("#importPreview").innerHTML=`<div class="import-summary"><article><b>${raw.length}</b><span>Filas</span></article><article><b>${pendingImport.rows.length}</b><span>Válidas</span></article><article><b>${pendingImport.rows.filter(r=>(type==="empresas"?state.empresas:state.alumnos).some(x=>x.nombre.toLowerCase()===r.nombre.toLowerCase())).length}</b><span>Coincidencias</span></article></div><div class="import-table-wrap"><table><tbody>${pendingImport.rows.slice(0,10).map(r=>`<tr><td><b>${esc(r.nombre)}</b></td><td>${esc(r.empresa||r.sector||"")}</td><td>${esc(r.email||"")}</td><td>${esc(r.telefono||"")}</td></tr>`).join("")}</tbody></table></div>`}}
function confirmImport(){const arr=pendingImport.type==="empresas"?state.empresas:state.alumnos,update=$("#updateExisting").checked;let created=0,updated=0;pendingImport.rows.forEach(r=>{const ex=arr.find(x=>x.nombre.toLowerCase()===r.nombre.toLowerCase());if(ex&&update){Object.assign(ex,Object.fromEntries(Object.entries(r).filter(([k,v])=>k!=="id"&&v)));updated++}else if(!ex){arr.unshift(r);created++}});log(`Importación ${pendingImport.type}: ${created} añadidos, ${updated} actualizados`);scheduleSave();closeModal();show(pendingImport.type);toast(`${created} añadidos · ${updated} actualizados`)}
function exportExcel(type){const rows=type==="empresas"?state.empresas.map(e=>({nombre_empresa:e.nombre,sector:e.sector,subsector:e.subsector,ciudad:e.ciudad,isla:e.isla,web:e.web,fuente:e.fuente,acepta_practicas:e.acepta_practicas,tipo_practicas:e.tipo_practicas,ciclos_recomendados:e.ciclos_recomendados,contacto_nombre:e.contacto,contacto_email:e.email,contacto_telefono:e.telefono,estado_crm:e.estado,prioridad:e.prioridad,notas:e.notas})):state.alumnos.map(a=>({nombre:a.nombre,dni:a.dni,telefono:a.telefono,email:a.email,direccion:a.direccion,nss:a.nss,estado:a.estado,empresa:a.empresa,inicio:a.inicio,fin:a.fin,tutor:a.tutor,horas:a.horas,evaluacion:a.evaluacion,notas:a.notas}));if(window.XLSX){const ws=XLSX.utils.json_to_sheet(rows),wb=XLSX.utils.book_new();XLSX.utils.book_append_sheet(wb,ws,type);XLSX.writeFile(wb,type==="empresas"?"bloom_empresas.xlsx":"bloom_alumnos.xlsx")}else{const a=document.createElement("a");a.href=URL.createObjectURL(new Blob([JSON.stringify(rows,null,2)],{type:"application/json"}));a.download=type+".json";a.click()}}
function downloadTemplate(type){const rows=type==="empresas"?[{nombre_empresa:"Empresa Ejemplo",sector:"Administración",subsector:"Gestoría",ciudad:"Las Palmas de Gran Canaria",isla:"Gran Canaria",web:"",fuente:"",acepta_practicas:"por confirmar",tipo_practicas:"FP",ciclos_recomendados:"Administración",contacto_nombre:"RRHH",contacto_email:"rrhh@empresa.es",contacto_telefono:"928000000",estado_crm:"nueva",prioridad:"media",notas:""}]:[{nombre:"Nombre Alumno",dni:"00000000A",telefono:"600000000",email:"alumno@email.com",direccion:"",nss:"",estado:"sin asignar",empresa:"",inicio:"",fin:"",tutor:"",horas:"370",evaluacion:"",notas:""}];const ws=XLSX.utils.json_to_sheet(rows),wb=XLSX.utils.book_new();XLSX.utils.book_append_sheet(wb,ws,type);XLSX.writeFile(wb,type==="empresas"?"plantilla_empresas_bloom.xlsx":"plantilla_alumnos_bloom.xlsx")}
function downloadBackup(){const a=document.createElement("a");a.href=URL.createObjectURL(new Blob([JSON.stringify(state,null,2)],{type:"application/json"}));a.download="bloom-crm-backup.json";a.click()} function restoreBackup(ev){const r=new FileReader();r.onload=()=>{state=JSON.parse(r.result);scheduleSave();render()};r.readAsText(ev.target.files[0])}
function init(){initSupabase();$$("[data-view]").forEach(b=>b.onclick=()=>show(b.dataset.view));$("#loginBtn").onclick=()=>login("login");$("#signupBtn").onclick=()=>login("signup");$("#magicBtn").onclick=magic;$("#globalSearch").oninput=globalSearch;$("#menuBtn").onclick=()=>$("#sidebar").classList.add("open");$("#notificationsBtn").onclick=openDrawer;$("#closeDrawer").onclick=closeDrawer;$("#overlay").onclick=closeDrawer;$("#quickBtn").onclick=()=>quickEvent(today());$("#userBtn").onclick=()=>show("ajustes");sb.auth.onAuthStateChange(async()=>{const {data}=await sb.auth.getUser();user=data.user;if(user)await bootstrap();else document.body.classList.add("locked")});sb.auth.getUser().then(({data})=>{user=data.user;if(user)bootstrap();else document.body.classList.add("locked")})}



/* =========================================================
   Bloom CRM 5.1 — Login corregido
   - No se queda bloqueado en "Entrando..."
   - Si Supabase Auth funciona pero faltan tablas, entra en Ajustes
   - Botón para probar conexión
   - SQL visible/descargable desde la pantalla de login
========================================================= */

async function safeBootstrap51(){
  try{
    initSupabase();
    const { data, error } = await sb.auth.getUser();
    if(error) throw error;

    user = data.user;
    if(!user){
      document.body.classList.add("locked");
      setAuth("Inicia sesión para acceder.");
      return;
    }

    document.body.classList.remove("locked");
    setAuth("Sesión iniciada.", "ok");

    try{
      await loadAll();
      show(current || "dashboard");
      toast("Bienvenida a Bloom CRM 🌸");
    }catch(loadError){
      console.error("loadAll after login", loadError);
      state = emptyState();
      setSync("Configuración pendiente", "error");
      current = "ajustes";
      show("ajustes");
      alert(
        "Has iniciado sesión correctamente, pero Bloom no puede cargar las tablas privadas.\n\n" +
        "Esto suele significar que falta ejecutar el SQL de Bloom CRM 5.1 en Supabase.\n\n" +
        "Te llevo a Ajustes para descargar el SQL completo."
      );
    }
  }catch(error){
    console.error("safeBootstrap51", error);
    document.body.classList.add("locked");
    setAuth(error.message || "No se pudo iniciar sesión.", "error");
  }
}

login = async function(mode){
  initSupabase();

  const email = $("#loginEmail")?.value?.trim();
  const password = $("#loginPassword")?.value || "";

  if(!email || !password){
    setAuth("Introduce email y contraseña.", "error");
    return;
  }

  try{
    setAuth(mode === "signup" ? "Creando cuenta..." : "Entrando...", "info");

    const res = mode === "signup"
      ? await sb.auth.signUp({ email, password })
      : await sb.auth.signInWithPassword({ email, password });

    if(res.error) throw res.error;

    /* Si Supabase requiere confirmación de email, no habrá sesión todavía */
    const { data } = await sb.auth.getSession();
    if(!data.session){
      setAuth("Cuenta creada. Revisa tu correo para confirmar el email antes de entrar.", "ok");
      return;
    }

    await safeBootstrap51();
  }catch(error){
    console.error("login51", error);
    let msg = error.message || "No se pudo entrar.";

    if(msg.toLowerCase().includes("invalid login credentials")){
      msg = "Email o contraseña incorrectos. Si todavía no tienes cuenta, pulsa “Crear cuenta”.";
    }
    if(msg.toLowerCase().includes("email not confirmed")){
      msg = "Tu email todavía no está confirmado. Revisa tu correo o usa enlace mágico.";
    }

    setAuth(msg, "error");
  }
};

magic = async function(){
  initSupabase();
  const email = $("#loginEmail")?.value?.trim();
  if(!email){
    setAuth("Introduce tu email.", "error");
    return;
  }

  try{
    setAuth("Enviando enlace mágico...", "info");
    const { error } = await sb.auth.signInWithOtp({
      email,
      options:{ emailRedirectTo: location.href.split("#")[0] }
    });
    if(error) throw error;
    setAuth("Revisa tu correo para entrar con el enlace mágico.", "ok");
  }catch(error){
    setAuth(error.message || "No se pudo enviar el enlace.", "error");
  }
};

async function testSupabase51(){
  initSupabase();
  try{
    setAuth("Probando conexión con Supabase...", "info");
    const { data, error } = await sb.auth.getSession();
    if(error) throw error;
    setAuth(data.session ? "Conexión correcta y sesión activa." : "Conexión correcta. Falta iniciar sesión.", "ok");
  }catch(error){
    setAuth("Error de conexión: " + (error.message || error), "error");
  }
}

function downloadSchemaFromLogin51(){
  downloadSchema();
}

/* Mejora Ajustes para indicar claramente si falta SQL */
const renderAjustesBase51 = renderAjustes;
renderAjustes = function(){
  renderAjustesBase51();
  const ajustes = $("#ajustes .grid-2");
  if(ajustes && !$("#setupHelp51")){
    ajustes.insertAdjacentHTML("afterbegin", `
      <div id="setupHelp51" class="card table-card setup-help">
        <h3>Estado de configuración</h3>
        <p>Usuario activo: <b>${esc(user?.email || "sin sesión")}</b></p>
        <p>Si acabas de instalar Bloom CRM 5.1, ejecuta el SQL completo una vez en Supabase SQL Editor.</p>
        <button class="primary" onclick="downloadSchema()">Descargar SQL completo</button>
        <button class="soft-btn" onclick="loadAll().then(render).catch(e=>alert(e.message))">Probar carga de datos</button>
      </div>
    `);
  }
};

/* Reemplaza init para evitar dobles bootstraps infinitos */
init = function(){
  initSupabase();

  $$("[data-view]").forEach(b=>b.onclick=()=>show(b.dataset.view));
  $("#loginBtn").onclick=()=>login("login");
  $("#signupBtn").onclick=()=>login("signup");
  $("#magicBtn").onclick=magic;

  /* Botones extra en login */
  const authForm = document.querySelector(".auth-form");
  if(authForm && !$("#testSupabaseBtn51")){
    authForm.insertAdjacentHTML("beforeend", `
      <button id="testSupabaseBtn51" type="button" class="soft-btn">Probar conexión</button>
      <button id="schemaLoginBtn51" type="button" class="soft-btn">Descargar SQL</button>
    `);
    $("#testSupabaseBtn51").onclick = testSupabase51;
    $("#schemaLoginBtn51").onclick = downloadSchemaFromLogin51;
  }

  $("#globalSearch").oninput=globalSearch;
  $("#menuBtn").onclick=()=>$("#sidebar").classList.add("open");
  $("#notificationsBtn").onclick=openDrawer;
  $("#closeDrawer").onclick=closeDrawer;
  $("#overlay").onclick=closeDrawer;
  $("#quickBtn").onclick=()=>quickEvent(today());
  $("#userBtn").onclick=()=>show("ajustes");

  let booting = false;
  sb.auth.onAuthStateChange(async (event) => {
    if(booting) return;
    if(event === "SIGNED_IN" || event === "TOKEN_REFRESHED" || event === "INITIAL_SESSION"){
      booting = true;
      await safeBootstrap51();
      booting = false;
    }
    if(event === "SIGNED_OUT"){
      user = null;
      state = emptyState();
      document.body.classList.add("locked");
      setAuth("Sesión cerrada.");
    }
  });

  sb.auth.getSession().then(async ({data})=>{
    if(data.session) await safeBootstrap51();
    else document.body.classList.add("locked");
  });
};

/* Forzar nuevo init limpio después de cargar */
document.addEventListener("DOMContentLoaded", () => {
  /* Si la versión anterior ya ejecutó init y quedó bloqueada, re-vinculamos */
  try{
    $("#loginBtn").onclick=()=>login("login");
    $("#signupBtn").onclick=()=>login("signup");
    $("#magicBtn").onclick=magic;
  }catch{}
});

init();
